import logo from "./logo.svg";
import "./App.css";
import { render } from "@testing-library/react";
import { useState } from "react";
import { db } from "./db.js";

function App() {
  return (
    <div className="App">
      <header>Weight Calc</header>
      <WeightInputForm />
    </div>
  );
}
function WeightInputForm() {
  // Array to store the weights from the weight inputs
  const [weightInputs, setWeightInputs] = useState([]);
  // Stores the result of calculating the weight layout
  const [weightLayout, setWeightLayout] = useState("");
  // Stores the desired weight
  const [weightTarget, setWeightTarget] = useState(0);
  // Stores the bar weight
  const [barWeight, setBarWeight] = useState(0);
  // Stores the saved layouts
  const [savedLayouts, setSavedLayouts] = useState(() => {
    let ret = [];
    async function populate() {
      const lays = await db.layouts.toArray();
      if (lays.length !== 0) {
        for (let i = 0; i < lays.length; i++) {
          ret = [...ret, lays[i].name];
        }
      }
    }
    populate().then(() => {
      ret.sort();
      setSavedLayouts(ret);
      setChosenSavedLayout(ret[0]);
    });
    return ret;
  });
  // Stores the selected saved layout to load
  const [chosenSavedLayout, setChosenSavedLayout] = useState("");
  // Comparator to sort the weightInputs (A, B) array by weight (B - A for descending order)
  const sortWeightInputs = (inputA, inputB) => {
    return Number(inputB.weight) - Number(inputA.weight);
  };
  // Handles changes in the weight inputs
  const handleFormChange = (index, event) => {
    let data = [...weightInputs];
    data[index][event.target.name] = event.target.value;
    setWeightInputs(data);
  };
  // Adds a weight input field
  const addWeightInput = () => {
    let newWeightInput = { weight: "", amount: "" };
    setWeightInputs([...weightInputs, newWeightInput]);
  };
  // Removes the index-th weight input field
  const removeWeightInput = (index) => {
    let data = [...weightInputs];
    data.splice(index, 1);
    setWeightInputs(data);
  };
  // Calculates the weight layout for given weights and target
  // Runs after clicking the "Calculate" button
  const calculateWeights = (e) => {
    e.preventDefault();
    const weights = weightInputs.map((input) => {
      return { weight: input.weight * 100, amount: input.amount };
    });
    weights.sort(sortWeightInputs);
    if (weightTarget - barWeight === 0) {
      setWeightLayout("Just the bar");
      return;
    }
    const toRet = weightCalc((weightTarget - barWeight) * 100, weights);
    let toLayout;
    if (toRet != null) {
      toLayout = "Use ";
      for (const weight of toRet.keys()) {
        toLayout += `${toRet.get(weight)} ${weight / 100}s, `;
      }
      toLayout = toLayout.slice(0, toLayout.length - 2);
    } else toLayout = "Unable to make desired weight";
    setWeightLayout(toLayout);
  };
  // Implements the calculation of the weights
  const weightCalc = (target, weights) => {
    const combos = new Map();
    let sum = 0;
    for (let i = 0; i < weights.length; i++) {
      let diff = target - sum;
      let numWeights = Math.floor(diff / weights[i]["weight"] / 2) * 2;
      if (numWeights === 0) continue;
      let added = Math.min(
        numWeights,
        Math.floor(weights[i]["amount"] / 2) * 2
      );
      sum += added * weights[i]["weight"];
      combos.set(weights[i].weight, added);
      weights[i].amount -= added;
      if (sum === target) return combos;
    }
    return null;
  };
  // Saves the current layout into the dexie db
  /* const saveCurrentLayout = (layout) => {
    const name = prompt("Enter exercise name: ");
    async function saveLayout(layout) {
      try {
        const id = await db.layouts.add(name, layout);
        return `Saved ${name} with id: ${id}`;
      } catch (error) {
        return `Failed to save: ${error}`;
      }
    }
    console.log(saveLayout(layout));
  }; */
  const saveCurrentLayout = () => {
    let name;
    async function saveLayout() {
      try {
        name = prompt("Enter exercise name:").toLowerCase();
        if (!name) throw new Error("No name entered");
        const id = await db.layouts.add({
          name,
          weightInputs,
          weightTarget,
          barWeight,
          weightLayout,
        });
        console.log(`Successfully stored ${name} with id: ${id}`);
      } catch (error) {
        console.log(`Failed to add with error: ${error}`);
      }
    }
    saveLayout().then(() => {
      if (name) addSavedLayout(name);
    });
  };
  // Handles adding a new saved layout option
  const addSavedLayout = (name) => {
    let newVersion = [...savedLayouts, String(name)].sort();
    setSavedLayouts(newVersion);
    setChosenSavedLayout(name);
  };
  /*
  const loadPrevLayout = async (targetName) => {
    const inputs = await db.layouts.get({ exerciseName: targetName });
    if (!inputs) return;
    const n = weightInputs.length;
    for (let i = 0; i < n; i++) {
      removeWeightInput(0);
    }
    inputs.map(addWeightInput);
    for (let i = 0; i < weightInputs.length; i++) {
      weightInputs[i].weight = inputs[i].weight;
      weightInputs[i].amount = inputs[i].amount;
    }
  }; */
  const loadPrevLayout = () => {
    async function load() {
      const exercise = chosenSavedLayout;
      /* const lay = await db.layouts.toArray();
      for (const x of lay) {
        if (x.name === exercise) console.log(x);
      } */
      const lay = await db.layouts.where("name").equals(exercise).toArray();
      setWeightInputs(lay[0].weightInputs);
      setWeightTarget(lay[0].weightTarget);
      setBarWeight(lay[0].barWeight);
      setWeightLayout(lay[0].weightLayout);
    }
    load().then();
  };
  // Saves the layout options
  const saveOptions = () => {
    db.savedLayouts.add(savedLayouts).then(console.log("saved options"));
  };
  return (
    <div className="weight-calculator">
      <div className="button-bar">
        <button
          type="button"
          id="save-layout"
          onClick={() => saveCurrentLayout(weightInputs)}
        >
          Save Layout
        </button>

        <select
          value={chosenSavedLayout}
          onChange={(event) => {
            setChosenSavedLayout(event.target.value);
          }}
        >
          {savedLayouts.map((savedLayout, index) => {
            return <option key={index}>{savedLayout}</option>;
          })}
        </select>
        <button type="button" id="load-layout" onClick={loadPrevLayout}>
          Load Layout
        </button>
        <button
          type="button"
          id="clear-db"
          onClick={() => {
            async function clearAll() {
              await db.delete();
              db.open(3);
              console.log("Cleared database");
              setSavedLayouts([]); // clear select options bc they're no longer saved
            }
            clearAll();
          }}
        >
          Clear DB
        </button>
        <button type="button" id="saveLayoutOptions" onClick={saveOptions}>
          Save Layout Options
        </button>
        <button
          type="button"
          id="loadOptions"
          onClick={() => {
            async function getOptions() {
              let options = await db.savedLayouts.toArray();
              console.log(options);
            }
            getOptions().then();
          }}
        >
          Load Options
        </button>
      </div>
      <p>{weightLayout}</p>
      <form className="weight-input-form">
        <div className="target-weight">
          <label htmlFor="target-weight-input">Target Weight:</label>
          <input
            type="tel"
            value={weightTarget}
            id="target-weight-input"
            onChange={(event) => {
              setWeightTarget(event.target.value);
            }}
          ></input>
        </div>
        <div className="bar-info">
          <label htmlFor="bar-weight">Bar Weight:</label>
          <input
            type="tel"
            id="bar-weight"
            value={barWeight}
            onChange={(event) => {
              setBarWeight(event.target.value);
            }}
          />
          <label htmlFor="bar-type">Bar Type:</label>
          <select id="bar-type">
            <option>Barbell</option>
            <option>Dumbbell</option>
          </select>
        </div>
        <div className="weight-input-fields">
          {weightInputs.map((input, index) => {
            return (
              <div key={index} className="weight-input">
                <label htmlFor={`weight-input${index}`}>Weight:</label>
                <input
                  type="tel"
                  id={`weight-input${index}`}
                  name="weight"
                  value={input.weight}
                  onChange={(event) => handleFormChange(index, event)}
                />
                <label htmlFor={`weight-amount${index}`}>Amount:</label>
                <input
                  type="tel"
                  name="amount"
                  id={`weight-amount${index}`}
                  value={input.amount}
                  onChange={(event) => handleFormChange(index, event)}
                />
                <button type="button" onClick={() => removeWeightInput(index)}>
                  Remove
                </button>
              </div>
            );
          })}
          <button type="button" onClick={addWeightInput}>
            Add weight
          </button>
        </div>
        <button type="button" onClick={calculateWeights}>
          Calculate
        </button>
      </form>
    </div>
  );
}

export default App;
